svg.script:
// ===== CORE STATE =====
// Inputs
let cyclicX = 0;   // Roll: -1 (Left) to 1 (Right)
let cyclicY = 0;   // Pitch: -1 (Fwd) to 1 (Aft)
let pedal = 0.5;   // Tail thrust: 0 (Left/None) to 1 (Right max). Default 0.5 to hover.
let cgOffset = 0;  // -1 (Aft) to 1 (Fwd)

// Physics State
let driftSpeedX = 0;
let groundPosX = 0;
let pitchAngle = 0; // Fuselage pitch
let rollAngle = 0;  // Fuselage roll
let crashState = false;

// Tuning Constants
const MAX_DISK_TILT_X = 12; // Degrees
const MAX_DISK_TILT_Y = 15; // Degrees
const MAIN_ROTOR_LIFT = 100; // Arbitrary units representing weight
const MAX_TAIL_THRUST = 20;  // Tail rotor max force
const NOMINAL_TORQUE = -10;  // Main rotor torque pushes fuselage left (requiring +10 TR thrust to counter)

// ===== GET ELEMENTS =====
const svgRoot = document.documentElement;

// Inputs
const pedalHitbox = document.getElementById('pedalHitbox');
const pedalKnob = document.getElementById('pedalKnob');
const cyclicHitbox = document.getElementById('cyclicHitbox');
const cyclicKnob = document.getElementById('cyclicKnob');
const cgHitbox = document.getElementById('cgHitbox');
const cgKnob = document.getElementById('cgKnob');
const autoTrimBtn = document.getElementById('autoTrimBtn');
const autoTrimText = document.getElementById('autoTrimText');

// Front View Elements (Translating Tendency)
const heliFrontSys = document.getElementById('heliFrontSys');
const heliFrontDisk = document.getElementById('heliFrontDisk');
const vecTailThrust = document.getElementById('vecTailThrust');
const lblTailThrust = document.getElementById('lblTailThrust');
const groundX = document.getElementById('groundX');
const latBalanceText = document.getElementById('latBalanceText');
const latBalanceDot = document.getElementById('latBalanceDot');

// Side View Elements (Pendulum/CG)
const heliSideSys = document.getElementById('heliSideSys');
const heliSideDisk = document.getElementById('heliSideDisk');
const cgPointVisual = document.getElementById('cgPointVisual');
const vecWeightSide = document.getElementById('vecWeightSide');
const lonBalanceText = document.getElementById('lonBalanceText');
const globalStatusText = document.getElementById('globalStatusText');

// ===== INPUT HANDLING =====
let activeDrag = null;

function getMouseCoords(e, element) {
  let clientX = e.clientX;
  let clientY = e.clientY;
  if (e.touches && e.touches.length > 0) {
    clientX = e.touches[0].clientX;
    clientY = e.touches[0].clientY;
  }
  const pt = svgRoot.createSVGPoint();
  pt.x = clientX;
  pt.y = clientY;
  const ctm = element.getScreenCTM().inverse();
  return pt.matrixTransform(ctm);
}

function handleDown(e, type) {
  e.preventDefault();
  activeDrag = type;
  handleMove(e);
}

function handleMove(e) {
  if (!activeDrag) return;
  e.preventDefault();

  if (activeDrag === 'pedal') {
    const pt = getMouseCoords(e, pedalHitbox);
    let val = pt.x / 290;
    pedal = Math.max(0, Math.min(1, val));
  } 
  else if (activeDrag === 'cg') {
    const pt = getMouseCoords(e, cgHitbox);
    let val = (pt.x / 290) * 2 - 1; // Map 0..290 to -1..1
    cgOffset = Math.max(-1, Math.min(1, val));
  }
  else if (activeDrag === 'cyclic') {
    const pt = getMouseCoords(e, cyclicHitbox);
    // Map 0..200 to -1..1
    let nx = (pt.x / 100) - 1;
    let ny = (pt.y / 100) - 1;

    // Constrain to circle
    const mag = Math.hypot(nx, ny);
    if (mag > 1) {
      nx /= mag;
      ny /= mag;
    }
    cyclicX = nx;
    cyclicY = ny;
  }
}

function handleUp() {
  activeDrag = null;
}

// Attach Listeners
pedalHitbox.addEventListener('mousedown', (e) => handleDown(e, 'pedal'));
pedalHitbox.addEventListener('touchstart', (e) => handleDown(e, 'pedal'), {passive: false});
cgHitbox.addEventListener('mousedown', (e) => handleDown(e, 'cg'));
cgHitbox.addEventListener('touchstart', (e) => handleDown(e, 'cg'), {passive: false});
cyclicHitbox.addEventListener('mousedown', (e) => handleDown(e, 'cyclic'));
cyclicHitbox.addEventListener('touchstart', (e) => handleDown(e, 'cyclic'), {passive: false});

window.addEventListener('mousemove', handleMove);
window.addEventListener('touchmove', handleMove, {passive: false});
window.addEventListener('mouseup', handleUp);
window.addEventListener('touchend', handleUp);

// Auto-Trim functionality
function autoTrim() {
  // Perfect hover values
  cgOffset = 0;
  pedal = 0.5; // Counters torque perfectly
  cyclicX = -0.15; // Counters translating tendency (Left cyclic)
  cyclicY = 0;
}
autoTrimBtn.addEventListener('click', autoTrim);
autoTrimText.addEventListener('click', autoTrim);


// ===== MAIN PHYSICS & UI LOOP =====
let lastTime = 0;
function animate(time) {
  const dt = (time - lastTime) / 1000 || 0.016;
  lastTime = time;

  // --- 1. UPDATE INPUT UI POSITIONS ---
  pedalKnob.setAttribute('transform', `translate(${pedal * 290}, 39)`);
  cgKnob.setAttribute('transform', `translate(${(cgOffset + 1) * 145}, 43)`);
  cyclicKnob.setAttribute('transform', `translate(${100 + cyclicX * 100}, ${100 + cyclicY * 100})`);

  // --- 2. CALCULATE TRANSLATING TENDENCY (FRONT VIEW) ---
  // Tail rotor thrust: maps from 0 to MAX_TAIL_THRUST
  let tailThrust = pedal * MAX_TAIL_THRUST;

  // Net lateral force = Torque + TailThrust + MainRotorLateralComponent
  // We assume Torque pushes left (-10), TR pushes right (+).
  // Main rotor tilts via cyclicX.
  let diskTiltRoll = cyclicX * MAX_DISK_TILT_X; // degrees
  let liftLateral = MAIN_ROTOR_LIFT * Math.sin(diskTiltRoll * Math.PI / 180);

  let netLateralForce = NOMINAL_TORQUE + tailThrust + liftLateral;

  // Acceleration and drift speed
  driftSpeedX += netLateralForce * dt * 5;
  // Add artificial dampening (air resistance)
  driftSpeedX *= 0.95; 

  // Update Ground visual
  groundPosX = (groundPosX - driftSpeedX) % 150;
  if (groundPosX < -150) groundPosX += 150;
  if (groundPosX > 150) groundPosX -= 150;
  groundX.setAttribute('transform', `translate(${210 + groundPosX}, 500)`);

  // Helicopter Roll Angle Calculation
  // If hovering stable, the body hangs straight down FROM the tilted disk? No, 
  // the disk tilts, pulling the mast. The body acts as a pendulum. 
  // In a stable hover with lateral force, the whole body leans to counter drift.
  // We'll approximate roll angle to be proportional to cyclic + drift momentum.
  let targetRoll = diskTiltRoll * 0.8 - (driftSpeedX * 0.5);
  rollAngle += (targetRoll - rollAngle) * 0.1;

  // Update Front View SVGs
  heliFrontSys.setAttribute('transform', `rotate(${rollAngle})`);
  // Disk tilts relative to body based on cyclic input
  heliFrontDisk.setAttribute('transform', `translate(0, -20) rotate(${diskTiltRoll})`);

  // Update Tail Thrust Vector
  let thrustLen = tailThrust * 3;
  if (thrustLen > 0) {
    vecTailThrust.setAttribute('x2', 40 - thrustLen);
    vecTailThrust.setAttribute('visibility', 'visible');
    lblTailThrust.setAttribute('visibility', 'visible');
    lblTailThrust.setAttribute('x', 35 - thrustLen);
  } else {
    vecTailThrust.setAttribute('visibility', 'hidden');
    lblTailThrust.setAttribute('visibility', 'hidden');
  }

  // Front UI Updates
  let latDotX = 270 + (netLateralForce * 4);
  latDotX = Math.max(180, Math.min(360, latDotX));
  latBalanceDot.setAttribute('cx', latDotX);

  if (Math.abs(netLateralForce) < 1.0 && Math.abs(driftSpeedX) < 1.0) {
    latBalanceText.textContent = "STABLE LATERAL HOVER";
    latBalanceText.setAttribute('fill', '#10b981');
    latBalanceDot.setAttribute('fill', '#10b981');
  } else if (netLateralForce > 0) {
    latBalanceText.textContent = "DRIFTING RIGHT (Apply Left Cyclic / Less Pedal)";
    latBalanceText.setAttribute('fill', '#ef4444');
    latBalanceDot.setAttribute('fill', '#ef4444');
  } else {
    latBalanceText.textContent = "DRIFTING LEFT (Apply Right Cyclic / More Pedal)";
    latBalanceText.setAttribute('fill', '#ef4444');
    latBalanceDot.setAttribute('fill', '#ef4444');
  }


  // --- 3. CALCULATE PENDULUM EFFECT & CG (SIDE VIEW) ---
  // CG offset mapping (Pixels from mast centerline)
  let cgPixelOffset = cgOffset * 35; // Max 35px forward/aft
  cgPointVisual.setAttribute('transform', `translate(${cgPixelOffset}, 5)`);

  // Disk Pitch Tilt
  let diskTiltPitch = cyclicY * MAX_DISK_TILT_Y;

  // The body hangs from the hub (pivot). Equilibrium is reached when the 
  // Main Lift vector passes exactly through the CG.
  // Hub is at (0, -80) relative to system. Body attachment is below.
  // Math simplification: Pitch angle naturally swings to place CG under the lifted disk.
  // Pitch equilibrium = Angle where Lift line hits CG.
  let h = 45; // vertical distance from hub to CG roughly
  let targetPitch = Math.atan2(cgPixelOffset, h) * (180 / Math.PI);

  // Cyclic tilts the disk, which creates a moment pulling the mast.
  targetPitch += diskTiltPitch;

  // Check for Crash Limits
  // If CG is max forward (+35px), it requires ~37deg pitch correction. 
  // If MAX_DISK_TILT is only 15deg, the pilot runs out of cyclic!
  crashState = false;
  let availableControl = diskTiltPitch - (cgOffset * 25); 

  if (Math.abs(availableControl) > 25) {
    crashState = true;
    // Nose dives or pitches up uncontrollably
    targetPitch = cgOffset > 0 ? 60 : -60; 
  }

  // Smooth pendulum swing
  pitchAngle += (targetPitch - pitchAngle) * 0.05;

  // Update Side View SVGs
  // Body hangs and rotates around the hub (0, -80)
  heliSideSys.setAttribute('transform', `translate(0, -80) rotate(${pitchAngle})`);
  // Disk tilts independently
  heliSideDisk.setAttribute('transform', `translate(0, -80) rotate(${-diskTiltPitch})`);

  // Keep weight vector pointing straight down regardless of pitch
  vecWeightSide.setAttribute('x2', -100 * Math.sin(pitchAngle * Math.PI/180));
  vecWeightSide.setAttribute('y2', 10 + 100 * Math.cos(pitchAngle * Math.PI/180));


  // Side UI Updates
  if (crashState) {
    lonBalanceText.textContent = "CRITICAL: CG OUT OF LIMITS! LOSS OF CONTROL!";
    lonBalanceText.setAttribute('fill', '#ef4444');
    cgKnob.firstElementChild.setAttribute('fill', '#ef4444');
  } else if (Math.abs(availableControl) < 5 && Math.abs(cgOffset) < 0.2) {
    lonBalanceText.textContent = "STABLE LONGITUDINAL HOVER";
    lonBalanceText.setAttribute('fill', '#10b981');
    cgKnob.firstElementChild.setAttribute('fill', '#10b981');
  } else if (cgOffset > 0) {
    lonBalanceText.textContent = `NOSE HEAVY (Apply Aft Cyclic to hold)`;
    lonBalanceText.setAttribute('fill', '#f59e0b');
    cgKnob.firstElementChild.setAttribute('fill', '#f59e0b');
  } else {
    lonBalanceText.textContent = `TAIL HEAVY (Apply Fwd Cyclic to hold)`;
    lonBalanceText.setAttribute('fill', '#f59e0b');
    cgKnob.firstElementChild.setAttribute('fill', '#f59e0b');
  }


  // --- 4. GLOBAL STATUS ---
  if (crashState) {
    globalStatusText.textContent = "WARNING: UNCONTROLLABLE AIRCRAFT";
    globalStatusText.setAttribute('fill', '#ef4444');
  } else if (Math.abs(netLateralForce) < 1.0 && Math.abs(driftSpeedX) < 1.0 && Math.abs(availableControl) < 5) {
    globalStatusText.textContent = "PERFECT STABLE HOVER";
    globalStatusText.setAttribute('fill', '#10b981');
  } else {
    globalStatusText.textContent = "UNSTABLE / DRIFTING / OUT OF TRIM";
    globalStatusText.setAttribute('fill', '#f59e0b');
  }

  requestAnimationFrame(animate);
}

// Start Simulation Loop
autoTrim(); // Start in a stable state
requestAnimationFrame(animate);
